class AsciiFreqGraph:
    def __init__(self, min_hz=400, max_hz=1000, rows=12, cols=60):
        self.min_hz = min_hz
        self.max_hz = max_hz
        self.rows = rows
        self.cols = cols
        self.history = []
    def add_point(self, freq_hz: int):
        freq_hz = max(self.min_hz, min(self.max_hz, freq_hz))
        self.history.append(freq_hz)

def enable_ansi_on_windows():
    if os.name != "nt":
        return True
    try:
        import ctypes
        kernel32 = ctypes.windll.kernel32
        handle = kernel32.GetStdHandle(-11)  
        mode = ctypes.c_uint32()
        if kernel32.GetConsoleMode(handle, ctypes.byref(mode)) == 0:
            return False

